INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-f0899a01-moex-00087', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '下列何種情形是禁止錯誤？', '["甲在路上看到乙拿槍追著丙開槍，乃持球棒將乙打傷使乙不能再追殺丙，實際上乙與丙僅是演 戲，為求逼真而沒有清場", "甲埋伏於乙宅門外，待有長得像乙的人走出大門，隨即開槍將其射殺，實際上甲射殺者為長得 像乙的乙之兄丙", "甲埋伏於乙宅門外欲射殺站在門前與人談話之乙，卻因射擊失準而命中與乙談話之丙", "外國人甲到我國後，以為在我國傳輸盜版影片並無法律規範，是合法的，乃架設收費網站分享 傳輸盜版影片"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00088', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '依照我國通說之見解，下列何者並非間接正犯？', '["導演甲將演員乙預定在戲中對人開槍的道具槍掉包為真槍，使乙在戲中以真槍射殺與甲有恩怨 之演員丙", "平日在家中對不服從之子女總是施以暴力使其屈服的甲，命令9歲之子乙到商店竊取吐司麵包 一袋", "18歲之乙身材極瘦小，甲誤會乙為小學生，與乙約定以1000元新臺幣為代價，要乙至大賣場 放火", "甲在警察巡邏時故意高呼救命，說乙要追殺自己，使警察誤以為乙欲攻擊甲而逮捕乙"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00089', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '依照我國實務見解，下列何種情形，應成立刑法第222條之加重強制性交罪？', '["甲、乙與丙一起喝酒後，甲、乙見丙酒醉昏倒不醒人事，乃共同對丙性交", "成年人甲與14歲之乙合意在公廁內口交", "成年人甲與11歲之乙合意在公廁內肛交", "成年人甲以玩具和錢取得6歲之乙同意，以陰莖放入乙口中為口交"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00090', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '下列何者並非刑法上的文書？', '["測量酒精濃度在儀器上顯示的數值", "繳稅通知單", "薪資單", "匯款單"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00091', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '下列何者屬於刑法第315條之1所定之「工具」？', '["近視眼鏡", "助聽器", "望遠鏡", "墊高身高用的木箱"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00092', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '下列敘述何者符合刑法有關數罪併罰的規定？', '["在同一案件數罪併罰而宣告拘役刑時，不適用易刑規定", "在同一案件中宣告死刑與拘役刑時，應該先執行拘役刑", "在同一案件中宣告有數個罰金刑時，應該執行累加的罰金刑", "在同一案件中宣告數個有期徒刑，執行刑應小或等於其總合"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00093', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '甲明知自己無資力仍搭乙所駕之計程車在市區內到處繞行，最後甲要乙停在一家超商前面，佯稱 要去超商內領錢支付車資，但是甲下車離去後即不復返。試問依我國實務見解，甲之行為應成立 下列何種犯罪？', '["詐欺取財罪", "竊盜罪", "侵占罪", "詐欺得利罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00094', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '下列那一項行為在我國不屬於犯罪行為？', '["使用竊盜", "入侵他人電腦", "收費提供竊錄場所", "免費提供儲藏贓物場所"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00095', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '依我國實務見解，下列何種情形，屬於中止未遂？', '["成年人甲男與 14 歲之乙女合意性交，因乙性器過小無法將陰莖插入，僅能以陰莖在乙外陰部 摩擦數次，於尚未接合前即停止", "甲男見乙女因自行吸食毒品而陷於精神缺陷無從抗拒之狀態，乃將乙衣服褪去並以陰莖欲插入 乙之陰道，但因乙尚有少許自保意識，虛弱地出手阻擋並口頭拒絕甲，甲乃停止其行為", "甲男見乙女因飲酒不勝酒力，乃將乙衣服褪去並以陰莖欲插入乙之陰道，但因乙奮力抵抗，未 能將陰莖插入乙之陰道，遂離開現場", "甲男見乙女於房內熟睡，乃將乙之內褲褪去，並以陰莖摩擦乙之臀部、外陰部，但因乙突然翻 身，甲亦受驚嚇，擔心事跡敗露，乃停手離開"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00096', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '下列敘述何者不符合偽證罪的規定？', '["必須知道自己的證述不符事實", "通譯也是會構成偽證罪的身分之一", "在警詢時為不實證述也是偽證罪涵蓋的範圍", "在不實證述之後才具結也是偽證罪涵蓋的範圍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
